import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/SideMenu.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className="side-menu-container">
      <div className="top-bar">
        <div className="menu-button" onClick={toggleSidebar}>
          <span></span>
          <span></span>
          <span></span>
        </div>
        <h1>Asthma Monitoring</h1>
        <div className="nav-buttons">
          <button onClick={() => navigate('/dashboard')} className="dashboard-button">
            Dashboard
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
          <button className="close-sidebar" onClick={toggleSidebar}>×</button>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>

      <div className={`main-content ${isSidebarOpen ? 'sidebar-open' : ''}`}>
        <h2>Recording Indicators</h2>
        <p>This page will contain the recording indicators functionality.</p>
      </div>
    </div>
  );
}

export default RecordingIndicators;
